import Foundation

enum Environment {
    case dev, prod, stage
}

class NetworkingManager {
    var environment = Environment.dev
    
    func url(for api: String) -> URL? {
        switch environment {
        case .dev:
            return URL(string: "https://api.example.com/\(api)")
        case .stage:
            return URL(string: "https://staging-api.example.com/\(api)")
        case .prod:
            return URL(string: "https://prod-api.example.com/\(api)")
        }
    }
    
    func performGetRequest(for api: String, completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = url(for: api) else { return }
        
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
            } else if let data = data {
                completion(.success(data))
            }
        }.resume()
    }
    
    func performPostRequest(for api: String, with jsonBody: Data, completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = url(for: api) else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = jsonBody
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
            } else if let data = data {
                completion(.success(data))
            }
        }.resume()
    }
}

let networkingManager = NetworkingManager()

// Authentication
networkingManager.performPostRequest(for: "authenticate", with: try! JSONSerialization.data(withJSONObject: ["username": "user1", "password": "pass123"]), completion: { result in
    switch result {
    case .success(let data):
        // Handle authentication response
        print(data)
    case .failure(let error):
        // Handle error
        print(error.localizedDescription)
    }
})

// Data Retrieval
